import{_ as B,C as s,o,c as n,a5 as e,b as a,w as A,a as d,E as l,a4 as r}from"./chunks/framework.gGRxziV4.js";const g=JSON.parse('{"title":"Everything Claude Code 深度解析系列 — 导读","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/index.md","filePath":"08-ECC教程/index.md","lastUpdated":null}'),C={name:"08-ECC教程/index.md"};function u(i,t,f,h,p,c){const E=s("Mermaid");return o(),n("div",null,[t[2]||(t[2]=e('<h1 id="everything-claude-code-深度解析系列-—-导读" tabindex="-1">Everything Claude Code 深度解析系列 — 导读 <a class="header-anchor" href="#everything-claude-code-深度解析系列-—-导读" aria-label="Permalink to &quot;Everything Claude Code 深度解析系列 — 导读&quot;">​</a></h1><blockquote><p><strong>一句话说清：</strong> ECC 就是给 Claude Code 装上操作系统的超级外挂。</p></blockquote><hr><h2 id="一个开发者的真实故事" tabindex="-1">一个开发者的真实故事 <a class="header-anchor" href="#一个开发者的真实故事" aria-label="Permalink to &quot;一个开发者的真实故事&quot;">​</a></h2><p>小明用上了 Claude Code，一开始很兴奋——TA 真的能写代码，而且写得还挺快！</p><p>但用了三天，小明开始抓头发：</p><p><strong>第一个坑：不记事。</strong> 昨天研究了一下午怎么配 OAuth，今天打开终端，TA 完全不记得了。小明得把整个背景重新说一遍。这就像你每次开会都要从头自我介绍一样，太累了。你可能会想，那就别关终端呗？问题是项目有好几个，你不可能同时开一堆终端不关。而且就算你不关，Claude Code 的上下文窗口也是有限的——聊得多了，前面的内容就自动&quot;遗忘&quot;了。你精心调教了半天的上下文，一场长对话就没了。</p><p><strong>第二个坑：没规矩。</strong> 团队规定用 2 个空格缩进、变量用 camelCase、提交前要跑测试。但 Claude Code 哪管这些，写出来的东西风格跟团队代码格格不入。你得一条一条告诉 TA——每次都是。而且你跟 TA 说了&quot;用 2 个空格&quot;，TA 下一个文件又给你搞成 4 个了。更麻烦的是安全规范：你说&quot;不要在代码里写密码&quot;，TA 点头了，转头就把 API key 硬编码到了配置文件里。你不可能时时刻刻盯着 TA 的每一个操作。</p><p><strong>第三个坑：不会自己干活。</strong> 写完代码了，TA 就停在那儿。你得手动说&quot;跑一下测试&quot;、&quot;格式化一下&quot;、&quot;检查一下有没有 console.log&quot;。TA 就像一个需要你手把手推着走的机器人。你说&quot;改完文件要格式化&quot;，TA 记住了——但也就记住了这一次。下次你问别的问题，TA 又忘了。你得不断重复这些&quot;流程指令&quot;，烦不胜烦。</p><p>小明崩溃了：「你这么聪明，怎么就不会自己管理自己呢？」</p><p><strong>这就是 ECC 解决的问题。</strong></p><hr><h2 id="ecc-怎么解决这三个痛点" tabindex="-1">ECC 怎么解决这三个痛点？ <a class="header-anchor" href="#ecc-怎么解决这三个痛点" aria-label="Permalink to &quot;ECC 怎么解决这三个痛点？&quot;">​</a></h2><p>ECC 把这三个痛点拆成了三组解决方案，正好对应学习路线的三个阶段：</p>',14)),(o(),a(r,null,{default:A(()=>[l(E,{id:"mermaid-40",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20PAIN%5B%22%F0%9F%98%A3%20%E4%B8%89%E4%B8%AA%E7%97%9B%E7%82%B9%22%5D%0A%20%20%20%20%20%20%20%20P1%5B%22%E4%B8%8D%E8%AE%B0%E4%BA%8B%5Cn%E6%AF%8F%E6%AC%A1%E5%AF%B9%E8%AF%9D%E4%BB%8E%E5%A4%B4%E6%9D%A5%22%5D%0A%20%20%20%20%20%20%20%20P2%5B%22%E6%B2%A1%E8%A7%84%E7%9F%A9%5Cn%E8%A7%84%E8%8C%83%E8%A6%81%E9%87%8D%E5%A4%8D%E8%AF%B4%22%5D%0A%20%20%20%20%20%20%20%20P3%5B%22%E4%B8%8D%E4%BC%9A%E8%87%AA%E5%B7%B1%E5%B9%B2%E6%B4%BB%5Cn%E6%B5%81%E7%A8%8B%E9%9D%A0%E6%89%8B%E5%8A%A8%E6%8E%A8%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20SOL%5B%22%F0%9F%98%8E%20ECC%20%E8%A7%A3%E5%86%B3%E6%96%B9%E6%A1%88%22%5D%0A%20%20%20%20%20%20%20%20S1%5B%22Hooks%20%E7%B3%BB%E7%BB%9F%5Cn%E8%87%AA%E5%8A%A8%E6%84%9F%E7%9F%A5%E3%80%81%E8%87%AA%E5%8A%A8%E8%AE%B0%E5%BF%86%22%5D%0A%20%20%20%20%20%20%20%20S2%5B%22Rules%20%2B%20Commands%20%2B%20Skills%5Cn%E8%A7%84%E7%9F%A9%E5%86%99%E6%AD%BB%EF%BC%8C%E4%B8%8D%E7%94%A8%E9%87%8D%E5%A4%8D%E8%AF%B4%22%5D%0A%20%20%20%20%20%20%20%20S3%5B%22Agents%20%E7%B3%BB%E7%BB%9F%5Cn%E4%B8%93%E5%AE%B6%E5%9B%A2%E9%98%9F%EF%BC%8C%E8%87%AA%E5%8A%A8%E7%BC%96%E6%8E%92%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20P1%20-.-%3E%20S1%0A%20%20%20%20P2%20-.-%3E%20S2%0A%20%20%20%20P3%20-.-%3E%20S3%0A%0A%20%20%20%20style%20P1%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20P2%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20P3%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A%20%20%20%20style%20S1%20fill%3A%234caf50%2Ccolor%3A%23fff%0A%20%20%20%20style%20S2%20fill%3A%232196f3%2Ccolor%3A%23fff%0A%20%20%20%20style%20S3%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A"})]),fallback:A(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e('<h3 id="记忆问题-→-hooks-系统" tabindex="-1">记忆问题 → Hooks 系统 <a class="header-anchor" href="#记忆问题-→-hooks-系统" aria-label="Permalink to &quot;记忆问题 → Hooks 系统&quot;">​</a></h3><p>Hooks 是 ECC 的&quot;神经系统&quot;。它在关键时刻自动触发动作：开始工作时自动加载上次的记忆，结束时自动保存状态。Claude Code 不再是失忆的鱼。</p><p>你不需要记住要保存什么、什么时候保存——Hooks 系统会自动帮你做。就像你用的编辑器自动保存一样，你写到一半电脑死机了，重启后文档还在，因为编辑器在背后默默帮你存盘了。Hooks 干的就是这件事。</p><h3 id="规矩问题-→-rules-commands-skills-系统" tabindex="-1">规矩问题 → Rules + Commands + Skills 系统 <a class="header-anchor" href="#规矩问题-→-rules-commands-skills-系统" aria-label="Permalink to &quot;规矩问题 → Rules + Commands + Skills 系统&quot;">​</a></h3><p>这三个模块一起构成 ECC 的&quot;规矩体系&quot;。</p><p><strong>Rules</strong> 定义底线：什么不能做、必须怎么做。比如&quot;提交前必须跑测试&quot;、&quot;不能用 console.log&quot;、&quot;变量命名用 camelCase&quot;。这些规矩一旦写好，每次 AI 工作时都会自动遵守，你不用反复说。</p><p><strong>Commands</strong> 封装常用操作：你经常要做的一套流程（比如&quot;规划 → 设计 → 写测试 → 写代码 → 审查&quot;），用一个 <code>/plan</code> 或 <code>/tdd</code> 就能触发，不用每次都从头描述。</p><p><strong>Skills</strong> 提供领域知识：遇到特定问题怎么处理。比如&quot;碰到构建错误怎么办&quot;、&quot;TypeScript 类型报错怎么排查&quot;。这些知识以&quot;菜谱&quot;的形式存储，AI 遇到问题时会自动查阅。</p><h3 id="自动化问题-→-agent-系统" tabindex="-1">自动化问题 → Agent 系统 <a class="header-anchor" href="#自动化问题-→-agent-系统" aria-label="Permalink to &quot;自动化问题 → Agent 系统&quot;">​</a></h3><p>Agent 系统是 ECC 的&quot;专家团队&quot;。不是让一个 AI 干所有事，而是让规划师拆任务、安全员审漏洞、测试员保质量、审查员把最后一关。</p><p>你只需要说&quot;我要做一个用户认证模块&quot;，系统就知道：先找规划师设计方案 → 安全员审查方案 → 测试员指导写测试 → 写完代码审查员过一遍。你不需要手动调度这些专家——系统帮你安排。</p><hr><h2 id="为什么叫-everything-claude-code" tabindex="-1">为什么叫&quot;Everything&quot; Claude Code？ <a class="header-anchor" href="#为什么叫-everything-claude-code" aria-label="Permalink to &quot;为什么叫&quot;Everything&quot; Claude Code？&quot;">​</a></h2><p>你可能会想：这名字是不是有点夸张？什么都是 Claude Code？</p><p>其实这里的&quot;Everything&quot;有两层意思：</p><p><strong>第一层：功能全覆盖。</strong> 记忆、规矩、自动化、安全、技能——一个 AI 编程助手需要的所有辅助系统，ECC 都帮你做好了。你不需要东拼西凑一堆工具。</p><p><strong>第二层：多 Harness 兼容。</strong> ECC 不只是给 Claude Code 用的。它支持 Codex、Cursor 等多种 AI Agent Harness。就像一个万能充电器，不管你的手机是什么牌子，插上就能用。</p><hr><h2 id="学习路线图" tabindex="-1">学习路线图 <a class="header-anchor" href="#学习路线图" aria-label="Permalink to &quot;学习路线图&quot;">​</a></h2><p>11 篇文章，分成三个区域。建议按顺序读，因为后面的会引用前面的概念：</p>',20)),(o(),a(r,null,{default:A(()=>[l(E,{id:"mermaid-97",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20ENTRY%5B%22%F0%9F%9F%A2%20%E5%85%A5%E9%97%A8%E5%8C%BA%EF%BC%88%E5%85%88%E8%AF%BB%E8%BF%99%E4%BA%9B%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20A1%5B%2201-%E9%A1%B9%E7%9B%AE%E5%85%A8%E6%99%AF%5Cn%E4%BA%86%E8%A7%A3%20ECC%20%E6%95%B4%E4%BD%93%E9%95%BF%E4%BB%80%E4%B9%88%E6%A0%B7%22%5D%0A%20%20%20%20%20%20%20%20A2%5B%2202-Hooks%E7%B3%BB%E7%BB%9F%5Cn%E7%90%86%E8%A7%A3%E8%87%AA%E5%8A%A8%E5%8C%96%E8%A7%A6%E5%8F%91%E5%99%A8%E8%BF%99%E4%B8%AA%E6%A0%B8%E5%BF%83%E6%A6%82%E5%BF%B5%22%5D%0A%20%20%20%20%20%20%20%20A3%5B%2203-Agent%E7%B3%BB%E7%BB%9F%5Cn%E8%AE%A4%E8%AF%86%E4%B8%93%E5%AE%B6%E5%9B%A2%E9%98%9F%E6%80%8E%E4%B9%88%E8%BF%90%E4%BD%9C%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20ADV%5B%22%F0%9F%9F%A1%20%E8%BF%9B%E9%98%B6%E5%8C%BA%EF%BC%88%E6%B7%B1%E5%85%A5%E4%BD%BF%E7%94%A8%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20B1%5B%2204-Commands%E7%B3%BB%E7%BB%9F%5Cn%E5%AD%A6%E4%BC%9A%E7%94%A8%E5%91%BD%E4%BB%A4%E5%BF%AB%E9%80%9F%E8%A7%A6%E5%8F%91%E5%8A%9F%E8%83%BD%22%5D%0A%20%20%20%20%20%20%20%20B2%5B%2205-Skills%E7%B3%BB%E7%BB%9F%5Cn%E4%BA%86%E8%A7%A3%20ECC%20%E6%80%8E%E4%B9%88%E6%89%A9%E5%B1%95%E6%8A%80%E8%83%BD%22%5D%0A%20%20%20%20%20%20%20%20B3%5B%2207-Rules%E7%B3%BB%E7%BB%9F%5Cn%E7%90%86%E8%A7%A3%E8%A7%84%E7%9F%A9%E6%80%8E%E4%B9%88%E5%AE%9A%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20PRO%5B%22%F0%9F%94%B4%20%E9%AB%98%E9%98%B6%E5%8C%BA%EF%BC%88%E6%B7%B1%E5%85%A5%E4%BA%86%E8%A7%A3%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20C1%5B%2206-Continuous-Learning%5CnAI%20%E6%80%8E%E4%B9%88%E8%87%AA%E6%88%91%E5%AD%A6%E4%B9%A0%22%5D%0A%20%20%20%20%20%20%20%20C2%5B%2208-%E8%B7%A8Harness%E9%80%82%E9%85%8D%5Cn%E4%B8%8D%E5%8F%AA%E6%98%AF%20Claude%20Code%22%5D%0A%20%20%20%20%20%20%20%20C3%5B%2209-%E5%B7%A5%E7%A8%8B%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%5Cn%E8%83%8C%E5%90%8E%E7%9A%84%E5%B7%A5%E7%A8%8B%E4%BD%93%E7%B3%BB%22%5D%0A%20%20%20%20%20%20%20%20C4%5B%2210-ECC%202.0%E4%B8%8E%E6%9C%AA%E6%9D%A5%5Cn%E6%9C%AA%E6%9D%A5%E4%BC%9A%E6%80%8E%E6%A0%B7%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20ENTRY%20--%3E%20ADV%20--%3E%20PRO%0A%0A%20%20%20%20style%20ENTRY%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%2Ccolor%3A%231b5e20%0A%20%20%20%20style%20ADV%20fill%3A%23fff8e1%2Cstroke%3A%23ff9800%2Ccolor%3A%23e65100%0A%20%20%20%20style%20PRO%20fill%3A%23fce4ec%2Cstroke%3A%23f44336%2Ccolor%3A%23b71c1c%0A%20%20%20%20style%20A1%20fill%3A%2381c784%2Ccolor%3A%23fff%0A%20%20%20%20style%20A2%20fill%3A%2381c784%2Ccolor%3A%23fff%0A%20%20%20%20style%20A3%20fill%3A%2381c784%2Ccolor%3A%23fff%0A%20%20%20%20style%20B1%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20B2%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20B3%20fill%3A%23ffb74d%2Ccolor%3A%23fff%0A%20%20%20%20style%20C1%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20C2%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20C3%20fill%3A%23e57373%2Ccolor%3A%23fff%0A%20%20%20%20style%20C4%20fill%3A%23e57373%2Ccolor%3A%23fff%0A"})]),fallback:A(()=>[...t[1]||(t[1]=[d(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e('<h3 id="推荐的阅读路径" tabindex="-1">推荐的阅读路径 <a class="header-anchor" href="#推荐的阅读路径" aria-label="Permalink to &quot;推荐的阅读路径&quot;">​</a></h3><p><strong>如果只有 1 小时：</strong> 读 01 → 02 → 03，了解核心三件套就够用了。这三篇会告诉你 ECC 长什么样、怎么自动运转、专家团队怎么协作。看完你就能判断 ECC 适不适合你。</p><p><strong>如果有一个下午：</strong> 读 01 → 02 → 03 → 04 → 05，完整了解怎么用。Commands 和 Skills 是日常使用中最常打交道的部分，看完你就能上手实操了。</p><p><strong>如果你想彻底搞懂：</strong> 按顺序全读，大约需要 5-6 小时。特别推荐第 06 篇（Continuous Learning）和第 08 篇（跨 Harness 适配），这两篇会打开你的视野，让你看到 AI Agent 系统设计的深层逻辑。</p><hr><h2 id="谁适合看这个系列" tabindex="-1">谁适合看这个系列？ <a class="header-anchor" href="#谁适合看这个系列" aria-label="Permalink to &quot;谁适合看这个系列？&quot;">​</a></h2><p><strong>刚用 Claude Code 的开发者。</strong> 你可能刚装上 Claude Code，发现 TA 用起来没想象中那么顺。看完这个系列你会理解：不是 TA 不行，是你没给 TA 装上合适的系统。就像一匹好马，没有马鞍和缰绳，你骑着当然难受。</p><p><strong>想提效的程序员。</strong> 你已经在用 Claude Code 了，但总觉得&quot;也就那样&quot;。Hooks、Agent、Skills 这些&quot;隐藏功能&quot;你可能都没碰过。看完你会解锁 Claude Code 的真正实力。</p><p><strong>技术负责人。</strong> 你想在团队里推广 AI 工具，但担心大家用法不一致、代码质量下降。ECC 提供了一套标准化的方案：规矩写死在 Rules 里，流程封装在 Commands 里，每个人用出来的东西是一致的。</p><p><strong>对 AI Agent 感兴趣的人。</strong> 你不一定要用 ECC，但 ECC 的设计思路非常值得学习。它是少数真正经历过生产环境考验的 Agent 系统，每一条设计决策背后都有&quot;血的教训&quot;。</p><p><strong>不需要你懂很多</strong> —— 每个概念我都会用比喻和图来解释，代码只在&quot;教你怎么做&quot;时才出现。如果你能看懂这篇文章，你就能看懂整个系列。</p><hr><h2 id="预计学习时间" tabindex="-1">预计学习时间 <a class="header-anchor" href="#预计学习时间" aria-label="Permalink to &quot;预计学习时间&quot;">​</a></h2><table tabindex="0"><thead><tr><th>篇目</th><th>时长</th><th>难度</th><th>核心收获</th></tr></thead><tbody><tr><td>01-项目全景</td><td>20 分钟</td><td>⭐</td><td>知道 ECC 长什么样</td></tr><tr><td>02-Hooks系统</td><td>30 分钟</td><td>⭐⭐</td><td>理解自动化怎么运转</td></tr><tr><td>03-Agent系统</td><td>30 分钟</td><td>⭐⭐</td><td>理解专家团队怎么协作</td></tr><tr><td>04-Commands系统</td><td>20 分钟</td><td>⭐</td><td>学会用命令触发功能</td></tr><tr><td>05-Skills系统</td><td>25 分钟</td><td>⭐⭐</td><td>了解技能扩展机制</td></tr><tr><td>06-Continuous-Learning</td><td>30 分钟</td><td>⭐⭐⭐</td><td>理解 AI 怎么自我进化</td></tr><tr><td>07-Rules系统</td><td>20 分钟</td><td>⭐⭐</td><td>掌握规矩制定方法</td></tr><tr><td>08-跨Harness适配</td><td>25 分钟</td><td>⭐⭐⭐</td><td>看到多平台兼容设计</td></tr><tr><td>09-工程基础设施</td><td>30 分钟</td><td>⭐⭐⭐</td><td>了解背后工程体系</td></tr><tr><td>10-ECC 2.0与未来</td><td>20 分钟</td><td>⭐</td><td>展望未来方向</td></tr></tbody></table><hr><h2 id="开始吧" tabindex="-1">开始吧 <a class="header-anchor" href="#开始吧" aria-label="Permalink to &quot;开始吧&quot;">​</a></h2><p>准备好了？从 <a href="./01-项目全景.html">01-项目全景</a> 开始。</p><p>不需要先安装什么——先了解它是什么，再决定要不要装。就像买车之前先试驾，看完这系列你自然会知道 ECC 适不适合你。</p>',18))])}const F=B(C,[["render",u]]);export{g as __pageData,F as default};
